#include <stdio.h>
int main() {
    int T, N, Q, K, A[50], count;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        scanf("%d", &Q);
        while (Q--) {
            scanf("%d", &K);
            count = 0;
            for (int i = 0; i < N; i++) {
                for (int j = i; j < N; j++) {
                    int min = A[i];
                    for (int k = i; k <= j; k++) {
                        if (A[k] < min) {
                            min = A[k];
                        }
                    }
                    if (min == K) {
                        count++;
                    }
                }
            }
            printf("%d\n", count);
        }
    }
    return 0;
}

