import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int[] A = new int[N];
            for (int i = 0; i < N; i++) {
                A[i] = sc.nextInt();
            }
            int Q = sc.nextInt();
            while (Q-- > 0) {
                int K = sc.nextInt();
                int count = 0;
                for (int i = 0; i < N; i++) {
                    for (int j = i; j < N; j++) {
                        int min = A[i];
                        for (int k = i; k <= j; k++) {
                            if (A[k] < min) {
                                min = A[k];
                            }
                        }
                        if (min == K) {
                            count++;
                        }
                    }
                }
                System.out.println(count);
            }
        }
    }
}

