const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];
const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const N = parseInt(readline());
    const A = readline().split(' ').map(x => parseInt(x));
    const Q = parseInt(readline());
    for (let j = 0; j < Q; j++) {
        const K = parseInt(readline());
        let count = 0;
        for (let k = 0; k < N; k++) {
            for (let l = k; l < N; l++) {
                const min = Math.min(...A.slice(k, l + 1));
                if (min === K) {
                    count++;
                }
            }
        }
        console.log(count);
    }
}
